// Gera a lista de URLs para os últimos 30 dias
const dias = 30;
const hoje = new Date();
const items = [];

for (let i = dias; i >= 0; i--) {
  const d = new Date(hoje);
  d.setDate(d.getDate() - i);
  const ano = d.getFullYear();
  const mes = String(d.getMonth() + 1).padStart(2, '0');
  const dia = String(d.getDate()).padStart(2, '0');
  const dataStr = `${ano}${mes}${dia}`;
  items.push({
    json: {
      tipo: 'omie',
      url: `https://www.omie.es/en/file-download?parents=marginalpdbcpt&filename=marginalpdbcpt_${dataStr}.1`
    }
  });
}

return items;

// Agrega todos os preços OMIE num único item
const todosPrecos = [];

for (const item of $input.all()) {
  const texto = item.json.data;
  if (!texto || typeof texto !== 'string') continue;
  for (const linha of texto.split('\n')) {
    const partes = linha.trim().split(';');
    if (partes.length >= 5 && /^\d{4}$/.test(partes[0].trim())) {
      const preco = parseFloat(partes[4].replace(',', '.'));
      if (!isNaN(preco)) todosPrecos.push(preco);
    }
  }
}

if (todosPrecos.length === 0) {
  return [{ json: { erro: 'Sem dados OMIE', todosPrecos: [] } }];
}

const mediaOmie = todosPrecos.reduce((a, b) => a + b, 0) / todosPrecos.length;

return [{
  json: {
    media_omie: mediaOmie,
    num_precos: todosPrecos.length
  }
}];

// ╔══════════════════════════════════════════════════════════════╗
// ║                    ⚙️  CONFIGURAÇÃO                          ║
// ╚══════════════════════════════════════════════════════════════╝

const CONFIG = {
  tarifario_atual_nome: "G9 | Vantagem+", 
  consumo_kwh: 700,   
  dias:         30,   
  potencia_kva: 6.90,     
  ciclo: "Simples", 

  // Valores ERSE 2026
  tar: { energia_kwh: 0.0607, potencia_dia: 0.3436 },
  indexado: { margem_kwh: 0.0150 } 
};

// ╔══════════════════════════════════════════════════════════════╗
// ║            LÓGICA DE PROCESSAMENTO (GANHOS)                 ║
// ╚══════════════════════════════════════════════════════════════╝

const TSE = 0.0026; 
const r = (v) => Math.round(v * 100) / 100;
const norm = (str) => (str || "").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").trim();

function parseCSVLine(line) {
  const columns = [];
  let current = '';
  let inQuotes = false;
  for (let i = 0; i < line.length; i++) {
    const char = line[i];
    if (char === '"') inQuotes = !inQuotes;
    else if (char === ',' && !inQuotes) {
      columns.push(current.trim());
      current = '';
    } else {
      current += char;
    }
  }
  columns.push(current.trim());
  return columns;
}

const omieData = $('Agregar OMIE').first().json;
const csvTexto = $input.first().json.data;
const mediaOmie = omieData.media_omie;

function processarCSV(csv) {
  const linhas = csv.split('\n').filter(l => l.length > 50);
  let fixos = [];
  let meuAtual = null;

  for (let i = 1; i < linhas.length; i++) {
    const col = parseCSVLine(linhas[i]);
    if (col.length < 11) continue;

    const nomeCompleto = col[1].replace(/"/g, '');
    const tipo         = col[3].replace(/"/g, '');
    const potKva       = parseFloat(col[8].replace(',', '.'));

    if (isNaN(potKva) || Math.abs(potKva - CONFIG.potencia_kva) > 0.1) continue;

    const pEnergiaBase = parseFloat(col[10].replace(',', '.'));
    const pPotenciaBase = parseFloat(col[9].replace(',', '.'));

    if (isNaN(pEnergiaBase) || pEnergiaBase <= 0) continue;

    const tarEnIncluida = (col[16] || "").toLowerCase().includes('true');
    const tarPotIncluida = (col[17] || "").toLowerCase().includes('true');
    const tseIncluida = (col[18] || "").toLowerCase().includes('true');

    const eFinal = pEnergiaBase + (tarEnIncluida ? 0 : CONFIG.tar.energia_kwh) + (tseIncluida ? 0 : TSE);
    const pFinal = pPotenciaBase + (tarPotIncluida ? 0 : CONFIG.tar.potencia_dia);

    const custoMensal = (eFinal * CONFIG.consumo_kwh) + (pFinal * CONFIG.dias);
    const info = { nome: nomeCompleto, custo: custoMensal };

    if (norm(nomeCompleto).includes(norm(CONFIG.tarifario_atual_nome))) {
      if (!meuAtual || custoMensal < meuAtual.custo) meuAtual = info;
    }

    if (norm(tipo).includes('fixo')) {
      fixos.push(info);
    }
  }

  return {
    atual: meuAtual,
    melhorFixo: fixos.sort((a,b) => a.custo - b.custo)[0]
  };
}

const resultado = processarCSV(csvTexto);

// Cálculo Indexado (Baseado na Média OMIE)
const precoKwhIndexado = (mediaOmie / 1000) + CONFIG.indexado.margem_kwh + CONFIG.tar.energia_kwh + TSE;
const custoIndexado = (CONFIG.consumo_kwh * precoKwhIndexado) + (CONFIG.dias * CONFIG.tar.potencia_dia);

const melhorFixo = resultado.melhorFixo || { nome: "Não encontrado", custo: 0 };
const meuCusto = resultado.atual ? resultado.atual.custo : 0;

// Cálculos de Ganho (Diferença para o Indexado)
const ganhoAtualVsIndexado = meuCusto > 0 ? meuCusto - custoIndexado : 0;
const ganhoFixoVsIndexado = melhorFixo.custo > 0 ? melhorFixo.custo - custoIndexado : 0;

// RESUMO
let resumo = `📊 *ANÁLISE DE ELETRICIDADE* (${new Date().toLocaleDateString('pt-PT')})\n`;
resumo += `━━━━━━━━━━━━━━━━━━━━\n\n`;
resumo += `⚡ *MERCADO (OMIE):*\n• Média 30 dias: ${r(mediaOmie)} €/MWh\n\n`;

if (resultado.atual) {
  resumo += `🏠 *TEU TARIFÁRIO ATUAL:*\n• ${resultado.atual.nome}\n• Custo: *${r(meuCusto)}€*\n`;
  resumo += `📉 *Ganho se mudar para Indexado:* +${r(ganhoAtualVsIndexado)}€/mês\n\n`;
}

resumo += `🏆 *MELHOR OPÇÃO FIXA:*\n• ${melhorFixo.nome}\n• Custo: ${r(melhorFixo.custo)}€\n`;
resumo += `📉 *Diferença para o Indexado:* +${r(ganhoFixoVsIndexado)}€/mês\n\n`;

resumo += `📈 *OPÇÃO INDEXADA (Média OMIE):*\n• Custo estimado: *${r(custoIndexado)}€*\n\n`;

resumo += `━━━━━━━━━━━━━━━━━━━━\n💡 *RECOMENDAÇÃO:*\n`;
resumo += `O Indexado é a opção mais barata. Mudar do teu atual para o Indexado poupa-te **${r(ganhoAtualVsIndexado)}€** por mês.`;

return [{ json: { 
  media_omie: r(mediaOmie), 
  custo_meu_atual: r(meuCusto),
  melhor_fixo_nome: melhorFixo.nome,
  custo_melhor_fixo: r(melhorFixo.custo),
  custo_indexado: r(custoIndexado),
  ganho_mensal: r(ganhoAtualVsIndexado),
  resumo 
} }];
